    eprintln!("[TEST] Mouse events: {:?}", events);

    if let Some(Event::Mouse(mouse)) = events.first() {
        eprintln!("[TEST] Mouse click at ({}, {})", mouse.x, mouse.y);
        // Handle click...
    }

    harness.finish(true);
    eprintln!("[TEST] PASS: E2E mouse click works");
