#[test]
fn test_e2e_bracketed_paste() {
    let mut harness = E2EHarness::new("input_output", "bracketed_paste", 80, 24);

    let buffer = EditBuffer::new();
    let mut view = EditorView::new(buffer);

    // Inject paste sequence
    let paste_input = b"\x1b[200~Pasted text\x1b[201~";
    let events = harness.inject_input(paste_input);

    eprintln!("[TEST] Paste events: {:?}", events);

